package {domain}

import (
	"context"

	"github.com/openmeterio/openmeter/pkg/pagination"
)

// Service is the domain interface.
type Service interface {
	Create(ctx context.Context, input CreateInput) (*{Domain}, error)
	Get(ctx context.Context, id string) (*{Domain}, error)
	List(ctx context.Context, params ListParams) (pagination.PagedResponse[{Domain}], error)
	Delete(ctx context.Context, id string) error
}

type CreateInput struct {
	Namespace string
	// ... domain fields
}

type ListParams struct {
	Namespace string
	pagination.Page
}

// service is the concrete implementation.
type service struct {
	adapter Adapter
}

func New(adapter Adapter) Service {
	return &service{adapter: adapter}
}

package main

import (
	"context"
	"os"

	"github.com/spf13/cobra"
	"github.com/spf13/viper"

	"github.com/openmeterio/openmeter/app/common"
)

func main() {
	var cfgFile string
	root := &cobra.Command{
		Use:          "{worker}",
		SilenceUsage: true,
		RunE: func(cmd *cobra.Command, args []string) error {
			ctx := cmd.Context()
			return run(ctx, cfgFile)
		},
	}
	root.PersistentFlags().StringVar(&cfgFile, "config", "config.yaml", "config file")
	if err := root.ExecuteContext(context.Background()); err != nil {
		os.Exit(1)
	}
}

func run(ctx context.Context, cfgFile string) error {
	v := viper.New()
	v.SetConfigFile(cfgFile)
	if err := v.ReadInConfig(); err != nil {
		return err
	}
	// Initialize app via Wire-generated provider:
	// app, cleanup, err := InitializeWorker(ctx, cfg)
	return nil
}

