@route("/api/v1/{resources}")
interface {Resource}Routes {
  @get
  @doc("List {resources}")
  list(
    @query namespace: string,
  ): {Resource}[] | OpenMeterError;

  @post
  @doc("Create a {resource}")
  create(@body body: Create{Resource}Request): {Resource} | OpenMeterError;

  @get
  @route("/{id}")
  @doc("Get a {resource} by id")
  get(@path id: string): {Resource} | OpenMeterError;

  @delete
  @route("/{id}")
  @doc("Delete a {resource}")
  delete(@path id: string): void | OpenMeterError;
}

package schema

import (
	"entgo.io/ent"
	"entgo.io/ent/schema/field"
	"entgo.io/ent/schema/index"
	"entgo.io/ent/schema/mixin"
)

// {Entity} holds the schema definition for the {Entity} entity.
type {Entity} struct {
	ent.Schema
}

// Fields of the {Entity}.
func ({Entity}) Fields() []ent.Field {
	return []ent.Field{
		field.String("id").Unique().Immutable(),
		field.String("namespace").NotEmpty(),
		field.Time("created_at").Immutable(),
		field.Time("updated_at"),
	}
}

// Indexes of the {Entity}.
func ({Entity}) Indexes() []ent.Index {
	return []ent.Index{
		index.Fields("namespace", "id").Unique(),
	}
}

// Mixin of the {Entity}.
func ({Entity}) Mixin() []ent.Mixin {
	return []ent.Mixin{
		mixin.Time{},
	}
}

// Edges of the {Entity}.
func ({Entity}) Edges() []ent.Edge {
	return nil
}

