	Namespace string          `json:"namespace"`
	ID        string          `json:"id"`
	CreatedAt time.Time       `json:"createdAt"`
	// ... domain-specific fields
}

func New{EventName}Event(namespace string, payload {EventName}Payload) (Event, error) {
	return Event{
		Type:      EventType{EventName},
		Namespace: models.NamespaceID{ID: namespace},
		Payload:   payload,
	}, nil
}

